async (params, browser) => {
  // Open Duolingo search
  await browser.open(`https://www.duolingo.com/profile/${params.query}`)

  // Wait for results
  await browser.waitForSelector('[data-test="profile-header"], h1, .profile-header', 15000)

  // Let results render
  await browser.wait(2500)

  // Extract results
  const search_results = await browser.evaluate(`const name = document.querySelector('h1, [data-test="profile-header"] h1')?.textContent?.trim() || ''; let streak = ''; let xp = ''; document.querySelectorAll('span, div, p').forEach(el => { const t = el.textContent; if (t.match(/day streak/i)) { const m = t.match(/(\d+)/); if (m) streak = m[1]; } if (t.match(/total.*xp/i) || t.match(/([\d,]+)\s*XP/i)) { const m = t.match(/([\d,]+)\s*XP/i); if (m) xp = m[1]; } }); return { display_name: name, streak, total_xp: xp, url: window.location.href };`)

  return search_results
}
